var $jq = jQuery.noConflict();

$jq(document).ready(function (){
     var expanded = false;
            // When clicked on the ghm-locator
            $jq("#ghm-locator").click(
                function(event) {
                    // Slide down div if hidden
                    if (!expanded) {
                        event.stopPropagation();
                        $jq("#header_slide_me_down").slideDown();
                        expanded = true;
                    }
                    // Slide up menu if shown
                    else {
                        $jq("#header_slide_me_down").slideUp();
                        expanded = false;
                    }
                }
            );
            // Hide div if clicked anywhere on the page
            $jq(document).click(
                function () {
                    if (expanded) {
                        $jq("#header_slide_me_down").slideUp();
                        expanded = false;
                    }
                }
            );
            // Prevent slideUp if clicked on the Menu div itself
            // (You can omit this part if you don't need it)
            $jq("#header_slide_me_down").click(
                function(event) {
                    event.stopPropagation();
                }
            );

		var globallanguage, globallocation;
        var audienceType = readCookie('AudienceTypes');
        var langval, locval, firstPart, secondPart, selectorselected, redirectURL, hrefVal,
        langselected, locselected, SiteUrl, SiteSelector;

        // create or update language cookie
             if(readCookie('language') == undefined || readCookie('language') == null){
               createCookie('language','English',1);
               globallanguage = readCookie('language');
             }
             else
               globallanguage = readCookie('language');

             // create or update location cookie
             if(readCookie('location') == undefined || readCookie('location') == null){
               createCookie('location','United States',1);
               createCookie('autoCountry','Yes',1);
               globallocation = readCookie('location');
             }
             else{
               globallocation = readCookie('location');
               if(readCookie('authid') != undefined || readCookie('authid') != null){
                createCookie('autoCountry','No',1);
               }
             }

               if(globallanguage != null)
                    globallanguage = globallanguage.toString().replace(/['"]+/g, '');
               if(globallocation != null)
                    globallocation = globallocation.toString().replace(/['"]+/g, '');

             $jq('#selectheaderLanguage option[value="' + globallanguage + '"]').attr('selected', 'selected');
             $jq('#selectlheaderPointOfInterest option[value="' + globallocation + '"]').attr('selected', 'selected');

        // Save - starts here
    	$jq("#btn-header-save").unbind().click(function(event){
             event.stopPropagation();
             event.preventDefault();
           langselected = $jq('#selectheaderLanguage :selected').val();
           locselected =  $jq('#selectlheaderPointOfInterest :selected').val();
          if (langselected === globallanguage && locselected === globallocation){
                          $jq("#header_slide_me_down").slideUp();
                          expanded = false;
                          return false;
          }
          if(audienceType != "Internal"){
             // Dynamically update the locale on selection of the language
             $jq('#selectheaderLanguage option').each(function() {

                 langval = $jq('#selectheaderLanguage :selected').data('defaultpath');
                 locval = $jq('#selectlheaderPointOfInterest :selected').data('defaultpath');

                 firstPart = langval.split('-')[0];
                 secondPart = langval.split('-')[1];
                 // selectorselected used to update the global selector icon
                 selectorselected = firstPart + "/" + locval;

                 redirectURL = decodeURIComponent(window.location);

             		if(redirectURL == null || redirectURL == "undefined"){
                         redirectURL = "/content/emc/en-us/home.html"
                    }
                 localeExInput = new RegExp("/"+countryLocale+"/");
                 // Page loads based on the language selected
             	 hrefVal = redirectURL.split(localeExInput).join("/"+langval+"/");
             		if (document.referrer != '' && document.referrer.indexOf('bpa_homepage') != -1) {
             			hrefVal = hrefVal.replace("/home.html", "/home/bpa_homepage.html");
             		}

				 deleteCookie('language');
				 deleteCookie('location');

                 SiteUrl = readCookie('GSSSiteUrl');
                    if(!SiteUrl || SiteUrl == "null")
                        createCookie('GSSSiteUrl',langval,9999);
                    else{
                         deleteCookie('GSSSiteUrl');
                         createCookie('GSSSiteUrl',langval,9999);
                         }

                 SiteSelector = readCookie('GSSSiteIcon');
                    if(!SiteSelector || SiteSelector == "null")
                      createCookie('GSSSiteIcon',selectorselected,9999);
                    else{
                      deleteCookie('GSSSiteIcon');
                      createCookie('GSSSiteIcon',selectorselected,9999);
                    }
                 // create a cookie for the saved selection of language and global location
                     createCookie('language',langselected,1);
                 	 createCookie('location',locselected,1);

                 // Redirect the page to the url of the language selected
                     if(redirectURL == hrefVal)
                        window.location.reload();
                     else
                        window.location = hrefVal;
                });
          }
          else{
            var langcookie  = readCookie("language");
            var loccookie = readCookie("location");

            if(langselected !== langcookie){
                    langval = $jq('#selectheaderLanguage :selected').data('defaultpath');
                    locval = $jq('#selectlheaderPointOfInterest option[value="' + loccookie + '"]').data('defaultpath');
                    firstPart = langval.split('-')[0];
                    secondPart = langval.split('-')[1];
                    // selectorselected used to update the global selector icon
                    selectorselected = firstPart + "/" + locval;

                    redirectURL = decodeURIComponent(window.location);

                    if(redirectURL == null || redirectURL == "undefined"){
                         redirectURL = "/content/emc/en-us/home.html"
                    }
                    localeExInput = new RegExp("/"+countryLocale+"/");
                    // Page loads based on the language selected
                    hrefVal = redirectURL.split(localeExInput).join("/"+langval+"/");
                    if (document.referrer != '' && document.referrer.indexOf('bpa_homepage') != -1) {
                       hrefVal = hrefVal.replace("/home.html", "/home/bpa_homepage.html");
                    }

                	deleteCookie('language');

                    SiteUrl = readCookie('GSSSiteUrl');
                    if(!SiteUrl || SiteUrl == "null")
                       createCookie('GSSSiteUrl',langval,9999);
                    else{
                       deleteCookie('GSSSiteUrl');
                       createCookie('GSSSiteUrl',langval,9999);
                    }

                    SiteSelector = readCookie('GSSSiteIcon');
                    if(!SiteSelector || SiteSelector == "null")
                        createCookie('GSSSiteIcon',selectorselected,9999);
                    else{
                        deleteCookie('GSSSiteIcon');
                        createCookie('GSSSiteIcon',selectorselected,9999);
                    }
                    // create a cookie for the saved selection of language and global location
                        createCookie('language',langselected,1);

                    if(locselected !== loccookie)
                    {
                       $jq("#internal-header-alert").modal('show');
                       $jq("#internalheaderalert").click(function(){
                            $jq('#internal-header-alert').modal('hide');
                                // Reloading the page to the locale selected
                                if(redirectURL != hrefVal)
                                    window.location = hrefVal;
                       });
                    }
                    if(locselected === loccookie){
                       if(redirectURL != hrefVal)
                           window.location = hrefVal;
                    }
            }
            else{
                    $jq("#internal-header-alert").modal('show');
                    $jq("#internalheaderalert").click(function(){
                        $jq('#internal-header-alert').modal('hide');
                        $jq('#selectlheaderPointOfInterest').val(loccookie);
                    });
                }
          }
        });

    if(audienceType == "Partner" || audienceType == "Customer" || audienceType == "ExternalX"){
        langval = $jq('#selectheaderLanguage :selected').data('defaultpath');
        locval = $jq('#selectlheaderPointOfInterest :selected').data('defaultpath');

        firstPart = langval.split('-')[0];
        secondPart = langval.split('-')[1];
        // selectorselected used to update the global selector icon
        selectorselected = firstPart + "/" + locval;

        SiteUrl = readCookie('GSSSiteUrl');
        if(!SiteUrl || SiteUrl == "null")
            createCookie('GSSSiteUrl',langval,9999);
        else{
            deleteCookie('GSSSiteUrl');
            createCookie('GSSSiteUrl',langval,9999);
        }

        SiteSelector = readCookie('GSSSiteIcon');

        if(!SiteSelector || SiteSelector == "null")
            createCookie('GSSSiteIcon',selectorselected,9999);
        else{
            deleteCookie('GSSSiteIcon');
            createCookie('GSSSiteIcon',selectorselected,9999);
        }
    }
});

